#include <stdio.h>
int main(void) {
    char *log = "2026-03-02 14:30:05 [INFO] pid=42 cpu=87";
    int year, month, day, hour, min, sec, pid, cpu;
    int n = sscanf(log, "%d-%d-%d %d:%d:%d %*s pid=%d cpu=%d",
                   &year, &month, &day, &hour, &min, &sec, &pid, &cpu);
    if (n == 8) {
        printf("Date: %04d/%02d/%02d\n", year, month, day);
        printf("Heure: %02d:%02d:%02d\n", hour, min, sec);
        printf("PID: %d\n", pid);
        printf("CPU: %d%%\n", cpu);
    } else {
        printf("Parse error: got %d fields\n", n);
    }
    return 0;
}

